  (() => {
    // --- HELPER 1: Chuẩn hóa text ---
    function normalizeText(str) {
      if (!str) return "";
      return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toUpperCase().trim();
    }

    // --- HELPER 2: Lấy số năm từ filter (VD: "4 năm" -> 4) ---
    function extractYearsFromFilter(str) {
      if (!str) return null;
      const match = str.match(/(\d+([.,]\d+)?)/);
      return match ? parseFloat(match[0].replace(',', '.')) : null;
    }

    // 1. LẤY DỮ LIỆU INPUT TỪ AI
    const vector = $json.query_vector || $json.vector; 
    let aiJson = {};
    try {
      // Cố gắng lấy JSON output từ node AI trước đó
      if ($('message refined') && $('message refined').item) {
          aiJson = $('message refined').item.json.parsed_json || 
                   JSON.parse($('message refined').item.json.output);
      }
    } catch (e) { aiJson = {}; }

    // KHỞI TẠO MẢNG ĐIỀU KIỆN "BẮT BUỘC" (AND LOGIC)
    let mustConditions = [];

    // ====================================================
    // A. LỌC THEO TÊN (CANDIDATE NAME)
    // ====================================================
    if (aiJson.filter_candidate_name) {
      const nameStr = aiJson.filter_candidate_name.trim();
      // Tìm chính xác hoặc tìm gần đúng tên
      mustConditions.push({ 
          "should": [
              { "key": "candidate_name", "match": { "text": nameStr } },
              { "key": "text", "match": { "text": nameStr } } // Dự phòng nếu tên nằm trong text
          ]
      });
    }

    // ====================================================
    // B. LỌC THEO KINH NGHIỆM (EXPERIENCE)
    // ====================================================
    if (aiJson.filter_experience) {
        const expRequest = aiJson.filter_experience.toLowerCase();
        const yearsRequested = extractYearsFromFilter(expRequest);

        if (yearsRequested !== null) {
            // Yêu cầu bạn đã có trường 'experience_years' (số thực) trong payload
            mustConditions.push({
                "key": "experience_years",
                "range": {
                    "gte": yearsRequested  // Lớn hơn hoặc bằng
                }
            });
        }
    }

    // ====================================================
    // C. LỌC THEO KỸ NĂNG (SKILLS)
    // ====================================================
    if (aiJson.filter_skills && Array.isArray(aiJson.filter_skills)) {
      aiJson.filter_skills.forEach(skill => {
        if (skill && skill.length < 50) { // Bỏ qua skill quá dài/rác
            mustConditions.push({
                "should": [
                    { "key": "skills_list", "match": { "text": skill } }, // Tìm trong mảng payload
                    { "key": "text", "match": { "text": skill } }         // Tìm trong nội dung text
                ]
            });
        }
      });
    }

    // ====================================================
    // D. LỌC THEO HỌC VẤN (EDUCATION) - MỚI
    // ====================================================
    if (aiJson.filter_education) {
       // Hỗ trợ cả string đơn lẻ hoặc mảng
       const eduList = Array.isArray(aiJson.filter_education) ? aiJson.filter_education : [aiJson.filter_education];

       eduList.forEach(edu => {
           if(edu && edu.length > 2) {
               // Tìm trường học hoặc bằng cấp trong payload hoặc text
               mustConditions.push({
                   "should": [
                       { "key": "school", "match": { "text": edu } }, // Nếu bạn lưu trường school
                       { "key": "major", "match": { "text": edu } },  // Nếu bạn lưu trường major
                       { "key": "text", "match": { "text": edu } }    // Tìm trong nội dung chung
                   ]
               });
           }
       });
    }

    // 2. CẤU HÌNH QUERY BODY
    let limit = $json.limit || 15;

    // Nếu không có filter nào cả -> Search rộng (30)
    // Nếu có filter -> Search cô đọng (15)
    if (mustConditions.length === 0) limit = 30;

    let body = {
      "vector": $json.query_vector,
      "limit": limit,
      "with_payload": true,

      // Quan trọng: Khi kết hợp nhiều trường (AND), khả năng vector score cao là thấp
      // Nhưng độ chính xác logic (Filter) lại tuyệt đối.
      // Nên set threshold = 0 để không lỡ mất ứng viên đúng tiêu chí.
      "score_threshold": 0 
    };

    // 3. NHÚNG FILTER VÀO BODY
    if (mustConditions.length > 0) {
      body.filter = {
        "must": mustConditions // Bắt buộc thỏa mãn TẤT CẢ điều kiện trên
      };
    }

    return JSON.stringify(body);
  })()
}}

